namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(5, 10, 50.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpectedPercentage(
        int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ValidInputs_ResultIsInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);

        // Assert.IsInRange verifies low <= actual <= high
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_ReturnsExactly100()
    {
        var result = _calculator.CalculatePercentage(20, 20);

        // Assert.IsGreaterThan verifies actual > lowerBound
        Assert.IsGreaterThan(99.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        var result = _calculator.CalculatePercentage(0, 10);

        // Assert.IsLessThan verifies actual < upperBound
        Assert.IsLessThan(1.0, result);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        var result = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GetGrade_NegativePercentage_ReturnsF()
    {
        var result = _calculator.GetGrade(-5.0);

        Assert.AreEqual("F", result);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50.0, 100.0);

        Assert.AreEqual(50.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_FullRawScore_Returns100()
    {
        var result = _calculator.NormalizeScore(100.0, 100.0);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        // Result should be clamped — never exceed 100
        Assert.IsLessThan(101.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 100.0);

        Assert.AreEqual(0.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_AlwaysInRange()
    {
        // Test several values and verify they all land in [0, 100]
        double[] rawScores = [0, 25, 50, 75, 100, 200];

        foreach (var raw in rawScores)
        {
            var result = _calculator.NormalizeScore(raw, 100.0);
            Assert.IsInRange(result, 0.0, 100.0);
            Assert.IsGreaterThan(-1.0, result);
        }
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}

