    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        // Result should be clamped — never exceed 100
        Assert.IsLessThan(101.0, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 100.0);

        Assert.AreEqual(0.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_AlwaysInRange()
    {
        // Test several values and verify they all land in [0, 100]
        double[] rawScores = [0, 25, 50, 75, 100, 200];

        foreach (var raw in rawScores)
        {
            var result = _calculator.NormalizeScore(raw, 100.0);
            Assert.IsInRange(result, 0.0, 100.0);
            Assert.IsGreaterThan(-1.0, result);
        }
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}

